//! # Tukey-bowl admission gate — the runtime twin of the quality-margin cert.
//!
//! This is the fold point for **just-in-time, speculative-precision
//! dequantization**: keep weights at a coarse code (Q4 / E_8 / Leech cell),
//! and *mask* a tile up to higher precision only at the instant it is used,
//! only where the mask is provably indistinguishable from the true
//! high-precision computation, and **miss (recompute), never lie**, everywhere
//! else.
//!
//! ## The bowl IS the Tukey biweight
//!
//! The admission rule proved Init-only in
//! `open-source/gnosis-math/Gnosis/QualityMarginCacheAdmissibility.lean` is:
//!
//! > if the true logits have a strict argmax with runner-up margin `gamma`, and
//! > a substituted (here: speculatively dequantized) vector differs from the
//! > truth by less than `tau` in sup-norm with `2 * tau <= gamma`, then the
//! > argmax is preserved — the substitution is gate-indistinguishable.
//!
//! That bound is exactly a **redescending M-estimator** with tuning constant
//! `c = gamma / 2`: a residual inside the bowl (`|r| < c`) gets full influence
//! (admit the mask); a residual past `c` redescends to **zero** influence
//! (`miss, not lie`). We use **Tukey's bisquare**:
//!
//! ```text
//!   w_c(r) = (1 - (r/c)^2)^2   for |r| <= c ,   0  for |r| > c
//!   psi_c(r) = r * w_c(r)        (bounded influence; zero past c)
//! ```
//!
//! The Lean docstring even names our enemy: the `bowl_q_filter` corruptor was
//! an *unbounded* bowl that violated `2 * tau <= gamma` and flipped the token
//! (`argmax_can_flip_when_bound_violated`). The redescend at `c = gamma/2` is
//! the fix the cert demands — a green status over a wrong answer is forbidden.
//!
//! ## Sound by measurement, not by estimate
//!
//! The gate does **not** hand-estimate `tau`. It takes the *measured* per-tile
//! sup-norm residual `||truth - draft||_inf` (or, when the truth is unavailable
//! at serve time, the certified cell covering bound) and checks `2 * tau <=
//! gamma` against the *observed* decision margin. The speculator's job is to
//! shrink the residual that survives; the gate's job is to certify it. This
//! keeps the worst-case gate sound without solving the open τ-estimation
//! problem (see `amplituhedron_tau`).
//!
//! ## Leech-turbo cadence (stride 11)
//!
//! Drafts are sampled on a stride that must be **coprime to the field carrier**
//! so the schedule cannot alias periodic weight structure (the "jamming" the
//! `packing_stride` work avoids). For the Leech field the first admissible
//! stride above the E_8 region (7, which *jams*) is **11** — the "leech-turbo"
//! winner, dual 19, `11 + 19 = 30 = h(E_8)`. This already shows up live as the
//! `spectral-6-e8-…-r11` FLUX residual runs.

#![allow(dead_code)]

// ── Lattice covering references (documented constants, NOT load-bearing) ─────
//
// The worst-case in-cell quantization error is the lattice *covering radius*.
// These are pinned here for reference / for a future certified worst-case gate;
// the runtime gate below uses the *measured* residual so it never asserts an
// unproven constant. Standard scaling (minimal norm as noted).

/// Cubic ℤⁿ: covering radius per coordinate = 1/2 (worst point is the cell
/// centre, distance √n·½). The baseline bowl — widest per unit density.
pub const COVER_CUBIC_PER_COORD: f64 = 0.5;
/// E_8 (standard, min norm² = 2): covering radius 1.0, packing radius 1/√2.
/// Covering/packing = √2; the bowl is rounder than cubic at equal density.
pub const COVER_E8_STANDARD: f64 = 1.0;
/// Leech Λ₂₄ (standard, min norm² = 4): covering radius √2, packing radius 1.
/// The roundest known bowl in 24-D — the tightest certified mask region.
pub const COVER_LEECH_STANDARD: f64 = std::f64::consts::SQRT_2;

// ── Leech-turbo stride (coprime cadence) ────────────────────────────────────

/// Leech field carrier = the 24-D kissing number, `196560 = 2^4·3^3·5·7·13`.
/// A draft stride is admissible iff coprime to this (no shared prime ⇒ no
/// aliasing/jamming). Note `7 | 196560` (jams) but `11 ∤ 196560` (admits).
pub const LEECH_FIELD_CARRIER: u64 = 196_560;

/// E_8 Coxeter number `h(E_8) = 30 = 2·3·5`. The leech-turbo pair sums to it:
/// `11 + 19 = 30`.
pub const E8_COXETER: u64 = 30;

/// The winning leech-turbo draft stride.
pub const LEECH_TURBO_STRIDE: u64 = 11;
/// Its dual (OSI-toroidal) stride; `LEECH_TURBO_STRIDE + LEECH_TURBO_DUAL = 30`.
pub const LEECH_TURBO_DUAL: u64 = 19;

#[inline]
fn gcd(mut a: u64, mut b: u64) -> u64 {
    while b != 0 {
        let t = b;
        b = a % b;
        a = t;
    }
    a
}

/// A draft stride is admissible to a field carrier iff it is coprime to it.
/// Coprime stride ⇒ the residual-draft schedule shares no period with the
/// weight stream ⇒ no jamming.
#[inline]
pub fn stride_admissible(stride: u64, carrier: u64) -> bool {
    stride > 0 && gcd(stride, carrier) == 1
}

/// First admissible stride `>= from` for the carrier, scanning up to `limit`
/// steps. For the Leech field starting at the jamming 7 this returns 11.
pub fn first_admissible_stride_from(from: u64, carrier: u64, limit: u64) -> u64 {
    let mut s = from.max(1);
    let mut steps = 0;
    while steps < limit {
        if stride_admissible(s, carrier) {
            return s;
        }
        s += 1;
        steps += 1;
    }
    s
}

// ── Tukey bisquare (the bowl) ───────────────────────────────────────────────

/// Tukey bisquare **weight** `w_c(r)` at tuning constant `c = gamma / 2`.
/// `(1 - (r/c)^2)^2` inside the bowl, redescending to **0** past `c`. This is
/// the graded admission influence of a residual `r`.
#[inline]
pub fn tukey_weight(r: f64, c: f64) -> f64 {
    if c <= 0.0 {
        return 0.0;
    }
    let u = r / c;
    if u.abs() >= 1.0 {
        0.0
    } else {
        let t = 1.0 - u * u;
        t * t
    }
}

/// Tukey bisquare **ρ** (the bounded loss): `1 - (1 - (r/c)^2)^3` inside,
/// saturating at `1` past `c`. Cited for completeness; the gate uses the
/// weight and the hard `2τ≤γ` predicate.
#[inline]
pub fn tukey_rho(r: f64, c: f64) -> f64 {
    if c <= 0.0 {
        return 1.0;
    }
    let u = r / c;
    if u.abs() >= 1.0 {
        1.0
    } else {
        let t = 1.0 - u * u;
        1.0 - t * t * t
    }
}

/// Tukey bisquare **ψ** (the influence): `r · w_c(r)`, bounded and **zero past
/// `c`** — the formal statement of "miss, not lie": a residual beyond the
/// half-margin exerts no pull on the masked value.
#[inline]
pub fn tukey_psi(r: f64, c: f64) -> f64 {
    r * tukey_weight(r, c)
}

// ── The admission gate (runtime twin of QualityMarginCacheAdmissibility) ─────

/// Outcome of gating one masked tile.
#[derive(Clone, Copy, Debug, PartialEq)]
pub enum Admission {
    /// The mask is gate-indistinguishable from the true high-precision tile
    /// (`2·τ ≤ γ`). Carry the dequantized draft. `weight` is the Tukey
    /// influence in `[0,1]` (1 well inside the bowl, → 0 toward the rim).
    Admit { tau: f64, weight: f64 },
    /// The cell is too coarse for the local margin (`2·τ > γ`). **Miss, not
    /// lie**: the caller must take a real high-precision load for this tile.
    Miss { tau: f64 },
}

impl Admission {
    #[inline]
    pub fn is_admit(&self) -> bool {
        matches!(self, Admission::Admit { .. })
    }
    #[inline]
    pub fn tau(&self) -> f64 {
        match *self {
            Admission::Admit { tau, .. } | Admission::Miss { tau } => tau,
        }
    }
}

/// Sup-norm (L∞) of the residual `truth - draft` — the exact quantity the Lean
/// `SupNormBelow` bounds. This is the per-tile `τ`.
#[inline]
pub fn sup_norm_residual(truth: &[f32], draft: &[f32]) -> f64 {
    debug_assert_eq!(truth.len(), draft.len());
    let mut m = 0.0f64;
    for i in 0..truth.len() {
        let e = (truth[i] - draft[i]).abs() as f64;
        if e > m {
            m = e;
        }
    }
    m
}

/// L2 norm of the residual `truth - draft` — the energy the certificate
/// `EnergyMarginBridgeAdmissibility` bounds (the norm a weight residual
/// actually propagates in, via the inner product `⟨τ, a⟩`).
#[inline]
pub fn l2_norm_residual(truth: &[f32], draft: &[f32]) -> f64 {
    debug_assert_eq!(truth.len(), draft.len());
    let mut s = 0.0f64;
    for i in 0..truth.len() {
        let e = (truth[i] - draft[i]) as f64;
        s += e * e;
    }
    s.sqrt()
}

/// **The gate.** Given the measured sup-norm residual `tau` of a speculatively
/// dequantized tile and the observed decision margin `gamma`, admit iff
/// `2·tau ≤ gamma` (the `QualityMarginCacheAdmissibility` rule), and grade the
/// admitted mask by the Tukey bisquare at `c = gamma/2`.
///
/// `gamma <= 0` (no margin) ⇒ always `Miss`: with no decision room, nothing is
/// safely maskable.
#[inline]
pub fn gate(tau: f64, gamma: f64) -> Admission {
    if gamma <= 0.0 {
        return Admission::Miss { tau };
    }
    // 2·τ ≤ γ  ⇔  τ ≤ γ/2 = c. Exactly the cert's premise.
    if 2.0 * tau <= gamma {
        let c = gamma * 0.5;
        Admission::Admit {
            tau,
            weight: tukey_weight(tau, c),
        }
    } else {
        Admission::Miss { tau }
    }
}

/// Convenience: gate a masked tile directly from `truth` and `draft` vectors.
#[inline]
pub fn gate_tile(truth: &[f32], draft: &[f32], gamma: f64) -> Admission {
    gate(sup_norm_residual(truth, draft), gamma)
}

/// **The energy gate** — the runtime twin of
/// `Gnosis.EnergyMarginBridgeAdmissibility.energy_gate_bounds_perturbation`.
/// Given the masking residual's **L2 norm** `tau_l2` and margin `gamma`, admit
/// iff `4·tau_l2² ≤ gamma²` (equivalently `2·tau_l2 ≤ gamma`), grading by the
/// Tukey bisquare at `c = gamma/2`. This is the norm a weight residual
/// propagates in (`⟨τ,a⟩ ≤ ‖τ‖₂·‖a‖₂` by Cauchy-Schwarz), and the norm where
/// the E_8/Leech bowl's tightness converts to certified accept-rate. `‖a‖₂` (the
/// read-out energy) folds into `gamma`; pass the margin already scaled by it.
#[inline]
pub fn gate_energy(tau_l2: f64, gamma: f64) -> Admission {
    if gamma <= 0.0 {
        return Admission::Miss { tau: tau_l2 };
    }
    // 4·τ² ≤ γ²  ⇔  2·τ ≤ γ (both nonneg). Matches the cert's `4‖τ‖²‖a‖²≤γ²`.
    if 4.0 * tau_l2 * tau_l2 <= gamma * gamma {
        Admission::Admit {
            tau: tau_l2,
            weight: tukey_weight(tau_l2, gamma * 0.5),
        }
    } else {
        Admission::Miss { tau: tau_l2 }
    }
}

/// Convenience: energy-gate a masked tile directly from `truth`/`draft`.
#[inline]
pub fn gate_tile_energy(truth: &[f32], draft: &[f32], gamma: f64) -> Admission {
    gate_energy(l2_norm_residual(truth, draft), gamma)
}

// ── The speculator seam ─────────────────────────────────────────────────────

/// A **precision speculator**: drafts a high-precision estimate of a tile from
/// its coarse code. The draft must lie in (or near) the code's cell; its
/// residual vs the truth is what the [`gate`] bounds. This is the single seam
/// every drafter implements so the race is apples-to-apples through identical
/// plumbing (lattice-predictor, distilled-head, self-recursion, …).
pub trait PrecisionSpeculator {
    /// Draft a high-precision estimate of the true tile into `out`, given the
    /// dequantized cell `centroid` (length = `out.len()`) and the cell edge
    /// `step`. Pure: no I/O, deterministic for a given input.
    fn draft(&self, centroid: &[f32], step: f32, out: &mut [f32]);
    /// Stable identifier for reporting / the race scoreboard.
    fn name(&self) -> &'static str;
}

/// Baseline speculator: the draft **is** the cell centroid (predict no in-cell
/// residual). This is exactly today's `kv_cache_e8` dequant behaviour, present
/// as the zero on the scoreboard the real speculators must beat.
#[derive(Clone, Copy, Debug, Default)]
pub struct CentroidSpeculator;

impl PrecisionSpeculator for CentroidSpeculator {
    #[inline]
    fn draft(&self, centroid: &[f32], _step: f32, out: &mut [f32]) {
        debug_assert_eq!(centroid.len(), out.len());
        out.copy_from_slice(centroid);
    }
    #[inline]
    fn name(&self) -> &'static str {
        "centroid"
    }
}

/// Aggregate result of masking a tile stream through a speculator + gate.
#[derive(Clone, Copy, Debug, Default)]
pub struct MaskReport {
    /// Tiles gated.
    pub tiles: usize,
    /// Tiles admitted (masked at Q-cost).
    pub admitted: usize,
    /// Tiles that missed → real high-precision load required.
    pub missed: usize,
    /// Mean Tukey influence over admitted tiles.
    pub mean_weight: f64,
    /// Mean sup-norm residual over all tiles.
    pub mean_tau: f64,
    /// Worst sup-norm residual over admitted tiles (must satisfy 2·τ ≤ γ).
    pub max_admitted_tau: f64,
}

impl MaskReport {
    /// Accept rate in `[0,1]` — the fraction of the network that runs at
    /// coarse-code cost with certified high-precision behaviour.
    #[inline]
    pub fn accept_rate(&self) -> f64 {
        if self.tiles == 0 {
            0.0
        } else {
            self.admitted as f64 / self.tiles as f64
        }
    }
}

/// Mask a stream of (truth, centroid) tile pairs through a speculator and the
/// gate at margin `gamma`, on the coprime draft `stride`. Tiles whose index is
/// not on the stride (or that miss) are counted as misses (real load). Returns
/// the scoreboard. The truth is supplied here only to *measure* the gate
/// offline; at serve time the gate uses the certified cell bound instead.
pub fn mask_stream<S: PrecisionSpeculator>(
    spec: &S,
    truths: &[Vec<f32>],
    centroids: &[Vec<f32>],
    step: f32,
    gamma: f64,
    stride: u64,
) -> MaskReport {
    assert_eq!(truths.len(), centroids.len(), "tile stream length mismatch");
    let mut rep = MaskReport::default();
    let mut draft = Vec::new();
    let mut weight_acc = 0.0f64;
    let mut tau_acc = 0.0f64;
    for (i, (t, c)) in truths.iter().zip(centroids.iter()).enumerate() {
        rep.tiles += 1;
        // Coprime cadence: only draft on the stride; off-stride tiles take the
        // centroid verbatim and are treated as a (free) pass-through miss.
        let on_stride = stride == 0 || (i as u64).is_multiple_of(stride);
        if !on_stride {
            rep.missed += 1;
            tau_acc += sup_norm_residual(t, c);
            continue;
        }
        draft.resize(c.len(), 0.0);
        spec.draft(c, step, &mut draft);
        let tau = sup_norm_residual(t, &draft);
        tau_acc += tau;
        match gate(tau, gamma) {
            Admission::Admit { weight, .. } => {
                rep.admitted += 1;
                weight_acc += weight;
                if tau > rep.max_admitted_tau {
                    rep.max_admitted_tau = tau;
                }
            }
            Admission::Miss { .. } => rep.missed += 1,
        }
    }
    rep.mean_weight = if rep.admitted > 0 {
        weight_acc / rep.admitted as f64
    } else {
        0.0
    };
    rep.mean_tau = if rep.tiles > 0 {
        tau_acc / rep.tiles as f64
    } else {
        0.0
    };
    rep
}

#[cfg(test)]
mod tests {
    use super::*;

    // ── Tukey bowl shape ────────────────────────────────────────────────────

    #[test]
    fn tukey_weight_is_one_at_centre_zero_past_c() {
        let c = 2.0;
        assert!((tukey_weight(0.0, c) - 1.0).abs() < 1e-12, "full influence at r=0");
        assert_eq!(tukey_weight(c, c), 0.0, "zero influence at the rim r=c");
        assert_eq!(tukey_weight(c * 1.5, c), 0.0, "redescended to zero past c");
        // Monotone decreasing on [0,c].
        let mut prev = tukey_weight(0.0, c);
        for k in 1..=20 {
            let r = c * k as f64 / 20.0;
            let w = tukey_weight(r, c);
            assert!(w <= prev + 1e-12, "bowl must be non-increasing outward");
            prev = w;
        }
    }

    #[test]
    fn tukey_psi_is_bounded_and_redescends() {
        let c = 1.0;
        // ψ is zero past c (the formal "miss, not lie").
        assert_eq!(tukey_psi(2.0, c), 0.0);
        assert_eq!(tukey_psi(-2.0, c), 0.0);
        // ψ is bounded: its magnitude never exceeds c on the whole line.
        let mut max_psi = 0.0f64;
        for k in -300..=300 {
            let r = k as f64 / 100.0;
            max_psi = max_psi.max(tukey_psi(r, c).abs());
        }
        assert!(max_psi < c, "bisquare influence is bounded below c, got {max_psi}");
    }

    // ── the gate mirrors the Lean cert ──────────────────────────────────────

    #[test]
    fn gate_admits_iff_two_tau_le_gamma() {
        // Worked example from QualityMarginCacheAdmissibility.lean: γ=4, τ=2,
        // 2τ=4 ≤ 4 ⇒ admissible (boundary, still admit since 2τ ≤ γ).
        assert!(gate(2.0, 4.0).is_admit(), "boundary 2τ=γ must admit");
        // τ just over half the margin ⇒ miss.
        assert!(!gate(2.001, 4.0).is_admit(), "2τ>γ must miss");
        // The flip witness: γ=2, τ=3, 2τ=6 > 2 ⇒ MUST miss (else Sardis).
        assert!(!gate(3.0, 2.0).is_admit(), "bound-violating mask must miss, not lie");
        // No margin ⇒ never admit.
        assert!(!gate(0.0, 0.0).is_admit(), "zero margin admits nothing");
    }

    #[test]
    fn admitted_weight_in_unit_interval() {
        for &(tau, gamma) in &[(0.0, 4.0), (1.0, 4.0), (1.9, 4.0), (2.0, 4.0)] {
            if let Admission::Admit { weight, .. } = gate(tau, gamma) {
                assert!((0.0..=1.0).contains(&weight), "weight {weight} out of [0,1]");
            }
        }
    }

    #[test]
    fn energy_gate_matches_the_cert_predicate() {
        // 4·τ² ≤ γ²  ⇔  2·τ ≤ γ. γ=4, τ=2 boundary admits; τ just over misses.
        assert!(gate_energy(2.0, 4.0).is_admit(), "2·2=4 ≤ 4 admits (boundary)");
        assert!(!gate_energy(2.001, 4.0).is_admit(), "2τ>γ energy-misses");
        assert!(!gate_energy(3.0, 2.0).is_admit(), "bound-violating energy mask must miss");
        assert!(!gate_energy(0.1, 0.0).is_admit(), "zero margin admits nothing");
        // L2 residual of [0.5,0,0] vs 0 is exactly 0.5 (0.5 is exact in f32);
        // energy-admits at the boundary γ=1.0 (4·0.25 = 1.0 ≤ 1.0).
        let t = [0.5f32, 0.0, 0.0];
        let z = [0.0f32, 0.0, 0.0];
        assert!((l2_norm_residual(&t, &z) - 0.5).abs() < 1e-9);
        assert!(gate_tile_energy(&t, &z, 1.0).is_admit());
        assert!(!gate_tile_energy(&t, &z, 0.999).is_admit());
    }

    #[test]
    fn sup_norm_is_l_infinity() {
        let t = [1.0f32, 2.0, 3.0];
        let d = [1.0f32, 2.5, 2.0];
        // residuals |0|,|−0.5|,|1.0| ⇒ sup = 1.0
        assert!((sup_norm_residual(&t, &d) - 1.0).abs() < 1e-6);
    }

    // ── leech-turbo stride ──────────────────────────────────────────────────

    #[test]
    fn leech_field_absorbs_seven_selects_eleven() {
        // 7 jams the Leech field; 11 is the first coprime stride above it.
        assert!(!stride_admissible(7, LEECH_FIELD_CARRIER), "7 | 196560 ⇒ jams");
        assert!(stride_admissible(11, LEECH_FIELD_CARRIER), "11 ∤ 196560 ⇒ admits");
        assert_eq!(
            first_admissible_stride_from(7, LEECH_FIELD_CARRIER, 32),
            LEECH_TURBO_STRIDE,
            "leech-turbo selects 11"
        );
    }

    #[test]
    fn leech_turbo_pair_sums_to_e8_coxeter() {
        assert_eq!(LEECH_TURBO_STRIDE + LEECH_TURBO_DUAL, E8_COXETER, "11+19=30=h(E8)");
    }

    #[test]
    fn carrier_factorization_is_as_documented() {
        // 196560 = 2^4 · 3^3 · 5 · 7 · 13. 11,17,19 are NOT factors.
        assert_eq!(LEECH_FIELD_CARRIER, 16 * 27 * 5 * 7 * 13);
        for p in [11u64, 17, 19] {
            assert_eq!(LEECH_FIELD_CARRIER % p != 0, true, "{p} must not divide the carrier");
        }
        for p in [2u64, 3, 5, 7, 13] {
            assert_eq!(LEECH_FIELD_CARRIER % p, 0, "{p} must divide the carrier");
        }
    }

    // ── centroid baseline + mask stream ─────────────────────────────────────

    #[test]
    fn centroid_speculator_drafts_the_centroid() {
        let spec = CentroidSpeculator;
        let c = [0.1f32, -0.2, 0.3, 0.0];
        let mut out = [0.0f32; 4];
        spec.draft(&c, 0.02, &mut out);
        assert_eq!(out, c, "centroid draft is the centroid");
        assert_eq!(spec.name(), "centroid");
    }

    #[test]
    fn mask_stream_scoreboards_admits_and_misses() {
        // Truths near their centroids ⇒ small residual ⇒ admits at a roomy γ.
        let centroids: Vec<Vec<f32>> = (0..30)
            .map(|i| vec![0.1 * i as f32, -0.05 * i as f32, 0.02 * i as f32, 0.0])
            .collect();
        // truth = centroid + tiny perturbation (well inside a γ=1.0 bowl).
        let truths: Vec<Vec<f32>> = centroids
            .iter()
            .map(|c| c.iter().map(|&x| x + 0.05).collect())
            .collect();
        let spec = CentroidSpeculator;
        let rep = mask_stream(&spec, &truths, &centroids, 0.02, 1.0, LEECH_TURBO_STRIDE);
        assert_eq!(rep.tiles, 30);
        // On stride 11: indices 0,11,22 are drafted; residual sup = 0.05,
        // 2τ=0.1 ≤ 1.0 ⇒ all on-stride tiles admit.
        assert_eq!(rep.admitted, 3, "indices 0,11,22 are on the stride and admit");
        assert_eq!(rep.missed, 27, "off-stride tiles are passthrough misses");
        assert!(rep.accept_rate() > 0.0);
        assert!(2.0 * rep.max_admitted_tau <= 1.0, "admitted tiles honour 2τ≤γ");
    }

    #[test]
    fn tight_margin_forces_all_miss() {
        let centroids: Vec<Vec<f32>> = (0..11).map(|_| vec![0.0f32; 4]).collect();
        // big residual vs a tiny margin ⇒ every draft must miss, not lie.
        let truths: Vec<Vec<f32>> = (0..11).map(|_| vec![1.0f32; 4]).collect();
        let spec = CentroidSpeculator;
        let rep = mask_stream(&spec, &truths, &centroids, 0.02, 0.001, 1);
        assert_eq!(rep.admitted, 0, "no mask may lie under a tight margin");
        assert_eq!(rep.missed, rep.tiles);
    }
}
